actions.script:
def appList = []
Map componentLocations = ec.factory.getComponentBaseLocations()

componentLocations.each { String compName, String location ->
    if (!location) return
    String path = location.startsWith("file:") ? location.substring(5) : location
    File compDir = new File(path)
    if (compDir.exists() && compDir.isDirectory()) {
        boolean hasSpec = new File(compDir, "spec").exists() || new File(compDir, "specs").exists()
        if (hasSpec) {
            def label = compName.split('-').collect{ it.capitalize() }.join(' ')
            appList.add([label: label, value: compName])
        }
    }
}

if (!appList.find { it.value == 'nursing-home' }) {
    appList.add([label: "Nursing Home Management", value: "nursing-home"])
}
context.apps = appList

import org.moqui.context.ExecutionContext
import groovy.json.JsonSlurper
ExecutionContext ec = context.ec

// Try looking in moqui-mce first
def registryFile = new File(ec.factory.runtimePath, "component/moqui-mce/registry/${type}s.json")
if (!registryFile.exists()) {
    // Fallback to moqui-ai for now if it exists
    registryFile = new File(ec.factory.runtimePath, "component/moqui-ai/registry/${type}s.json")
}

if (registryFile.exists()) {
    context.registry = new JsonSlurper().parse(registryFile)
} else {
    context.registry = [categories: []]
}
